import './nav.css';

function Nav() {

    const currentUser = useSelector((state) => state.user.currentUser)
    const dispatch = useDispatch();
    return (
    <div style={{ 
        marginTop: "150px", // דוחף את הטופס מתחת ל-Nav
        backgroundColor: "rgba(255, 0, 0, 0.2)", // רקע אדמדם בהיר כדי שנראה איפה הוא נמצא
        padding: "50px",
        minHeight: "300px" 
    }}>
        <h1 style={{color: "black"}}>דף התחברות</h1>
        <form onSubmit={handleSubmit}>
            <input type="text" placeholder="שם משתמש" value={username} onChange={(e) => setUsername(e.target.value)}/>
            <input type="password" placeholder="סיסמה" value={password} onChange={(e) => setPassword(e.target.value)}/>
            <button type="submit">התחבר</button>
        </form>
    </div>
);
}

export default Nav;
